async def worker(llm: ChatOpenAI, task_id: int):
    start_time = time.perf_counter()
    print(f"任务 {task_id} 开始于: {start_time:.2f}s")
    
    try:
        # 使用一个稍微需要点生成时间的 Prompt，方便观察
        response = await llm.ainvoke([HumanMessage(prompt)])
        end_time = time.perf_counter()
        duration = end_time - start_time
        print(f"任务 {task_id} 完成于: {end_time:.2f}s, 耗时: {duration:.2f}s")
        return duration
    except Exception as e:
        print(f"任务 {task_id} 报错: {e}")
        return None

async def main():
    llm = get_llm()
    tasks = [worker(llm, i) for i in range(5)]
    
    print(f"--- 开始并发测试 (5个并行请求) ---")
    overall_start = time.perf_counter()
    
    # 关键：使用 gather 真正实现并发
    await asyncio.gather(*tasks)
    
    overall_end = time.perf_counter()
    print(f"--- 测试结束 ---")
    print(f"总运行时间: {overall_end - overall_start:.2f}s")
    print(f"提示：如果总时间远小于各任务耗时之和，说明并行生效了。")

if __name__ == "__main__":
    asyncio.run(main())